const all_items = $input.all().map(item => item.json);

// 🔥 latest row (row_number MAX)
const latest_sheet = all_items
  .filter(item => item.today_post_mode !== undefined && item.today_post_mode !== '')
  .sort((a, b) => (b.row_number || 0) - (a.row_number || 0))[0] || {};

// 🔹 values
const account_name = (latest_sheet.account_name || 'thebitz420dotio').trim();
const platform = (latest_sheet.platform || 'instagram').trim();
const today_post_mode = (latest_sheet.today_post_mode || '').trim();

// 🔥 derive types
const fb_post_type = today_post_mode.includes('fb_image') ? 'image' : 'video';
const ig_post_type = today_post_mode.includes('ig_image') ? 'image' : 'video';

// 🔹 बाकी same
const all_images = all_items
  .filter(item => item.all_img_name)
  .map(item => ({ name: item.all_img_name, id: item.img_id }));

const used_image_names = all_items
  .filter(item => item.used_img_name !== undefined)
  .map(item => (item.used_img_name || '').trim())
  .filter(n => n !== '');

const last_used = used_image_names.length > 0
  ? used_image_names[used_image_names.length - 1]
  : '';

// sort images
all_images.sort((a, b) => {
  const na = parseInt((a.name || '').match(/^\d+/)?.[0] || '0', 10);
  const nb = parseInt((b.name || '').match(/^\d+/)?.[0] || '0', 10);
  return na - nb;
});

// remove used
const used_set = new Set(used_image_names);
const remaining_images = all_images.filter(img => !used_set.has(img.name));

return [{
  json: {
    all_images,
    remaining_images,
    last_used_name: last_used,
    account_name,
    platform,
    today_post_mode,
    fb_post_type,
    ig_post_type,
    total_images: all_images.length,
    remaining_count: remaining_images.length
  }
}];

const input = $input.first().json;
const all_images = input.all_images || [];
const remaining_images = input.remaining_images || [];
const last_used_name = (input.last_used_name || '').trim();
const account_name = input.account_name || 'thebitz420dotio';
const platform = input.platform || 'instagram';
const last_post_type = (input.last_post_type || '').trim();

if (all_images.length === 0) throw new Error('No images found in Drive folder!');

let selectedImage;
let nextPos;
let totalRemaining = remaining_images.length;

if (remaining_images.length === 0) {
  const lastUsedIndex = all_images.findIndex(img => img.name === last_used_name);
  const resetPos = (lastUsedIndex + 1) >= all_images.length ? 0 : lastUsedIndex + 1;
  selectedImage = all_images[resetPos];
  nextPos = resetPos;
  totalRemaining = all_images.length;
} else {
  const lastUsedIndexInAll = all_images.findIndex(img => img.name === last_used_name);
  let picked = remaining_images.find(
    img => all_images.findIndex(a => a.name === img.name) > lastUsedIndexInAll
  );
  if (!picked) picked = remaining_images[0];
  selectedImage = picked;
  nextPos = all_images.findIndex(a => a.name === picked.name);
}

let today_post_mode;
if (last_post_type === 'fb_image_ig_video') {
  today_post_mode = 'fb_video_ig_image';
} else {
  today_post_mode = 'fb_image_ig_video';
}

const fb_post_type = today_post_mode === 'fb_image_ig_video' ? 'image' : 'video';
const ig_post_type = today_post_mode === 'fb_image_ig_video' ? 'video' : 'image';

const productName = (selectedImage.name || 'Product')
  .replace(/^\d+_/, '')
  .replace(/\.[^.]+$/, '')
  .replace(/[-_]/g, ' ')
  .trim();

return [{
  json: {
    previous_image: last_used_name,
    next_index: nextPos + 1,
    total_images: all_images.length,
    remaining_images: totalRemaining,
    image_file_id: selectedImage.id,
    image_file_name: selectedImage.name,
    product_name: productName,
    account_name,
    platform,
    last_post_type,
    today_post_mode,
    fb_post_type,
    ig_post_type,
    image_drive_url: `https://drive.google.com/uc?export=download&id=${selectedImage.id}`
  }
}];

const computeItem = $('Compute Next Index & IG Type1').first().json;

const imageId = computeItem.image_file_id;
const imageName = computeItem.image_file_name;
const imageUrl = computeItem.image_drive_url;

const productName = (imageName || '')
  .replace(/^\d+_/, '')
  .replace(/\.[^.]+$/, '')
  .replace(/[-_]/g, ' ')
  .trim();

const imageBase = productName.toLowerCase().replace(/\s+/g, '');

let matchedDoc = null;
try {
  const allDocs = $('GDrive – List Product Docs1').all();
  for (const docItem of allDocs) {
    const docName = (docItem.json.name || '')
      .replace(/\.[^.]+$/, '')
      .toLowerCase()
      .replace(/[-_\s]/g, '');
    if (docName === imageBase) {
      matchedDoc = docItem.json;
      break;
    }
  }
} catch(e) {}

const docExportUrl = matchedDoc
  ? `https://docs.google.com/document/d/${matchedDoc.id}/export?format=txt`
  : null;

return [{
  json: {
    product_id: imageId,
    product_image_name: imageName,
    product_name: productName,
    doc_id: matchedDoc ? matchedDoc.id : null,
    doc_export_url: docExportUrl,
    has_doc: !!matchedDoc,
    product_image_url: imageUrl,
    product_description: matchedDoc
      ? `[Doc will be fetched] - ${matchedDoc.name}`
      : 'Premium product available now.',
    product_url: 'https://thebitz420.io'
  }
}];

