Product name: {{ $('Parse GDrive Product Data').item.json.product_name }}
Write a 2-3 sentence premium lifestyle description. Output only the description, nothing else.

parameters.jsCode:
const productData = $('Parse GDrive Product Data').first().json;
let description = productData.product_description || 'Premium product available now.';
try {
  const docResponse = $('Fetch Doc Text').first();
  const rawText = docResponse?.json?.data || docResponse?.json?.body || '';
  const cleaned = rawText.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  if (cleaned && cleaned.length > 10) description = cleaned.substring(0, 800);
} catch(e) {}
if (!description || description.includes('[Doc will be fetched]')) {
  try {
    const genData = $('GPT-4o – Generate Description').first()?.json || {};
    const genText = genData.output_text || genData.text || genData.content || genData.message?.content || genData.choices?.[0]?.message?.content || '';
    if (genText.trim()) description = genText.trim();
  } catch(e) {}
}
return [{ json: { ...productData, product_description: description } }];

const clean = (text) => (text || '').replace(/^\d+\.\s*/gm, '').replace(/\n+/g, ' ').replace(/\s+/g, ' ').trim();

let fbCaption = '🌿 Premium quality cannabis. Explore more 👉 https://thebitz420.io';
let igCaption = '🌿 New drop. Link in bio. #TheBitz420 #UKCannabis';

try { const d = $('Generate FB Caption').first()?.json || {};
  const t = d.output_text || d.text || d.content || d.message?.content || d.choices?.[0]?.message?.content || '';
  if (t.trim()) fbCaption = clean(t); } catch(e) {}

try { const d = $('Generate IG Caption5').first()?.json || {};
  const t = d.output_text || d.text || d.content || d.message?.content || d.choices?.[0]?.message?.content || '';
  if (t.trim()) igCaption = clean(t); } catch(e) {}

const productData = $('Merge Doc Text into Product').first().json;
return [{ json: { ...productData, facebook_caption: fbCaption, instagram_caption: igCaption } }];

