const item = $input.first();
const binary = item.binary.data;
if (!binary) throw new Error('No binary found');
const rawBase64 = await this.helpers.getBinaryDataBuffer(0, 'data').then(buffer => buffer.toString('base64'));
let mimeType = binary.mimeType || 'image/jpeg';
if (!rawBase64 || rawBase64.length < 100) throw new Error(`Base64 invalid (length: ${rawBase64.length})`);
return [{ json: { veo_image_base64: rawBase64, veo_image_mime_type: mimeType } }];

const productData = $('Compute Next Index & IG Type1').first().json;
const captionData = $('Merge Captions').first().json;

// 🔥 MODE FLIP LOGIC
const lastMode = productData.last_post_mode;

let nextMode = 'fb_image_ig_video';

if (lastMode === 'fb_image_ig_video') {
  nextMode = 'fb_video_ig_image';
} else if (lastMode === 'fb_video_ig_image') {
  nextMode = 'fb_image_ig_video';
}

// derive types
const fbPostType = nextMode.includes('fb_image') ? 'image' : 'video';
const igPostType = nextMode.includes('ig_image') ? 'image' : 'video';

// 🔽 FILE IDS
let imageFileId = '';
let videoFileId = '';

try { imageFileId = $('Upload AI Image to GDrive').first().json.id || ''; } catch(e) {}
try { videoFileId = $('Upload AI Video to GDrive').first().json.id || ''; } catch(e) {}

// 🔽 URL BUILD
const imageUrl = imageFileId
  ? `https://drive.google.com/uc?export=download&id=${imageFileId}`
  : productData.image_drive_url;

const videoUrl = videoFileId
  ? `https://drive.google.com/uc?export=download&id=${videoFileId}`
  : '';

// ✅ FINAL RETURN
return [{
  json: {
    ...productData,

    // ✅ IMPORTANT (override)
    today_post_mode: nextMode,
    fb_post_type: fbPostType,
    ig_post_type: igPostType,

    facebook_caption:  captionData.facebook_caption,
    instagram_caption: captionData.instagram_caption,

    final_image_url:   imageUrl,
    final_video_url:   videoUrl,

    image_file_id:     imageFileId,
    video_file_id:     videoFileId
  }
}];

const postData = $('Build Final Post Data1').first().json;

let fbPostId  = '';
let igPostId  = '';
let errorMessages = [];

const fbPostType = postData.fb_post_type;

if (fbPostType === 'image') {
  // TRUE branch: FB=Image, IG=Video
  try {
    const r = $('FB – Post Image').first().json;
    fbPostId = r.id || r.post_id || r.postId || '';
    if (r.error) errorMessages.push('FB Image: ' + JSON.stringify(r.error));
  } catch(e) { errorMessages.push('FB Image node error: ' + e.message); }

  try {
    const r = $('IG – Post Video (Image Day)').first().json;
    igPostId = r.id || r.video_id || r.videoId || r.postId || '';
    if (r.error) errorMessages.push('IG Video: ' + JSON.stringify(r.error));
  } catch(e) { errorMessages.push('IG Video node error: ' + e.message); }

} else {
  // FALSE branch: FB=Video, IG=Image
  try {
    const r = $('FB – Post Video (Video Day)').first().json;
    fbPostId = r.id || r.video_id || r.videoId || r.postId || '';
    if (r.error) errorMessages.push('FB Video: ' + JSON.stringify(r.error));
  } catch(e) { errorMessages.push('FB Video node error: ' + e.message); }

  try {
    const r = $('IG – Post Image (Video Day)').first().json;
    igPostId = r.id || r.post_id || r.postId || r.id || '';
    if (r.error) errorMessages.push('IG Image: ' + JSON.stringify(r.error));
  } catch(e) { errorMessages.push('IG Image node error: ' + e.message); }
}

// allSucceeded: at least one platform posted successfully
const allSucceeded = !!(fbPostId || igPostId);

return [{
  json: {
    ...postData,
    fb_post_id:     fbPostId,
    ig_post_id:     igPostId,
    all_succeeded:  allSucceeded,
    error_messages: errorMessages.join(' | '),
    posted_at:      new Date().toISOString()
  }
}];

