const postData = $('Build Final Post Data1').first().json;

let fbPostId  = '';
let errorMessages = [];
let isSuccess = false;

const fbPostType = postData.fb_post_type;

if (fbPostType === 'image') {
  try {
    const raw = $('FB – Post Image').first().json;
    const r = raw.results?.[0] || raw;

    fbPostId = r.id || r.post_id || r.postId || '';
    isSuccess = r.success === true || !!r.post_url || !!fbPostId;

    if (r.error) errorMessages.push('FB Image: ' + JSON.stringify(r.error));

  } catch(e) {
    errorMessages.push('FB Image node error: ' + e.message);
  }

} else {
  try {
    const raw = $('FB – Post Video (Video Day)').first().json;
    const r = raw.results?.[0] || raw;

    fbPostId = r.id || r.video_id || r.videoId || r.postId || '';
    isSuccess = r.success === true || !!r.post_url || !!fbPostId;

    if (r.error) errorMessages.push('FB Video: ' + JSON.stringify(r.error));

  } catch(e) {
    errorMessages.push('FB Video node error: ' + e.message);
  }
}

// final decision
const allSucceeded = isSuccess;

// 🔥 directly overwrite today_post_mode
const updated_today_post_mode = allSucceeded
  ? 'fb_video_ig_image'
  : 'fb_image_ig_video';

return [{
  json: {
    ...postData,
    fb_post_id: fbPostId,
    all_succeeded: allSucceeded,
    today_post_mode: updated_today_post_mode, // ✅ overwrite
    error_messages: errorMessages.join(' | '),
    posted_at: new Date().toISOString()
  }
}];
